import{_ as t,c as r,l as e,a as i,t as o,a4 as s,o as l}from"./chunks/framework.CzsDe1xi.js";const A=JSON.parse('{"title":"Horizontal Pod Autoscaling 详解","description":"","frontmatter":{"title":"Horizontal Pod Autoscaling 详解"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/HPA/horizontal-pod-autoscaling.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/HPA/horizontal-pod-autoscaling.md","lastUpdated":1709020051000}'),n={name:"doc/DevOps/Kubernetes/基础/HPA/horizontal-pod-autoscaling.md"},c={id:"frontmatter-title",tabindex:"-1"},p=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),h=s(`<p>应用的资源使用率通常都有高峰和低谷的时候，如何削峰填谷，提高集群的整体资源利用率，让 service 中的 Pod 个数自动调整呢？这就有赖于 Horizontal Pod Autoscaling 了，顾名思义，使 Pod 水平自动缩放。这个 Object（跟 Pod、Deployment 一样都是 API resource）也是最能体现 kubernetes 之于传统运维价值的地方，不再需要手动扩容了，终于实现自动化了，还可以自定义指标，没准未来还可以通过人工智能自动进化呢！</p><p>HPA 属于 Kubernetes 中的 <strong>autoscaling</strong> SIG（Special Interest Group），其下有两个 feature：</p><ul><li><a href="https://github.com/kubernetes/features/issues/117" target="_blank" rel="noreferrer">Arbitrary/Custom Metrics in the Horizontal Pod Autoscaler#117</a></li><li><a href="https://github.com/kubernetes/features/issues/118" target="_blank" rel="noreferrer">Monitoring Pipeline Metrics HPA API #118</a></li></ul><p>Kubernetes 自 1.2 版本引入 HPA 机制，到 1.6 版本之前一直是通过 kubelet 来获取监控指标来判断是否需要扩缩容，1.6 版本之后必须通过 API server、Heapseter 或者 kube-aggregator 来获取监控指标。</p><p>对于 1.6 以前版本中开启自定义 HPA 请参考 <a href="https://medium.com/@marko.luksa/kubernetes-autoscaling-based-on-custom-metrics-without-using-a-host-port-b783ed6241ac" target="_blank" rel="noreferrer">Kubernetes autoscaling based on custom metrics without using a host port</a>。</p><h2 id="hpa-解析" tabindex="-1">HPA 解析 <a class="header-anchor" href="#hpa-解析" aria-label="Permalink to &quot;HPA 解析&quot;">​</a></h2><p>Horizontal Pod Autoscaling 仅适用于 Deployment 和 ReplicaSet，在 v1 版本中仅支持根据 Pod 的 CPU 利用率扩缩容，在 v1alpha 版本中，支持根据内存和用户自定义的 metric 扩缩容。</p><p>如果你不想看下面的文章可以直接看下面的示例图，组件交互、组件的配置、命令示例，都画在图上了。</p><p>Horizontal Pod Autoscaling 由 API server 和 controller 共同实现。</p><h2 id="metrics-支持" tabindex="-1">Metrics 支持 <a class="header-anchor" href="#metrics-支持" aria-label="Permalink to &quot;Metrics 支持&quot;">​</a></h2><p>在不同版本的 API 中，HPA autoscale 时可以根据以下指标来判断：</p><ul><li>autoscaling/v1 <ul><li>CPU</li></ul></li><li>autoscaling/v1alpha1 <ul><li>内存</li><li>自定义 metrics <ul><li>kubernetes1.6 起支持自定义 metrics，但是必须在 kube-controller-manager 中配置如下两项： <ul><li><code>--horizontal-pod-autoscaler-use-rest-clients=true</code></li><li><code>--api-server</code> 指向 <a href="https://github.com/kubernetes/kube-aggregator" target="_blank" rel="noreferrer">kube-aggregator</a>，也可以使用 heapster 来实现，通过在启动 heapster 的时候指定 <code>--api-server=true</code>。查看 <a href="https://github.com/kubernetes/metrics" target="_blank" rel="noreferrer">kubernetes metrics</a></li></ul></li></ul></li><li>多种 metrics 组合 <ul><li>HPA 会根据每个 metric 的值计算出 scale 的值，并将最大的那个值作为扩容的最终结果。</li></ul></li></ul></li></ul><h2 id="使用-kubectl-管理" tabindex="-1">使用 kubectl 管理 <a class="header-anchor" href="#使用-kubectl-管理" aria-label="Permalink to &quot;使用 kubectl 管理&quot;">​</a></h2><p>Horizontal Pod Autoscaling 作为 API resource 也可以像 Pod、Deployment 一样使用 kubeclt 命令管理，使用方法跟它们一样，资源名称为 <code>hpa</code>。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hpa</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hpa</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> describe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hpa</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hpa</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>有一点不同的是，可以直接使用 <code>kubectl autoscale</code> 直接通过命令行的方式创建 Horizontal Pod Autoscaler。</p><p>用法如下：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> autoscale</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (-f </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">FILENAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TYPE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TYPE/NAME</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) [--min</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MINPODS] --max</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MAXPODS</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[--cpu-percent</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CPU] [flags] [options]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>举个例子：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> autoscale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deployment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> foo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --min=2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max=5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cpu-percent=80</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>为 Deployment foo 创建 一个 autoscaler，当 Pod 的 CPU 利用率达到 80% 的时候，RC 的 replica 数在 2 到 5 之间。</p><p><strong>注意</strong> ：如果为 ReplicaSet 创建 HPA 的话，无法使用 rolling update，但是对于 Deployment 来说是可以的，因为 Deployment 在执行 rolling update 的时候会自动创建新的 ReplicationController。</p><h2 id="什么是-horizontal-pod-autoscaling" tabindex="-1">什么是 Horizontal Pod Autoscaling？ <a class="header-anchor" href="#什么是-horizontal-pod-autoscaling" aria-label="Permalink to &quot;什么是 Horizontal Pod Autoscaling？&quot;">​</a></h2><p>利用 Horizontal Pod Autoscaling，kubernetes 能够根据监测到的 CPU 利用率（或者在 alpha 版本中支持的应用提供的 metric）自动的扩容 replication controller，deployment 和 replica set。</p><p>Horizontal Pod Autoscaler 作为 kubernetes API resource 和 controller 的实现。Resource 确定 controller 的行为。Controller 会根据监测到用户指定的目标的 CPU 利用率周期性得调整 replication controller 或 deployment 的 replica 数量。</p><h2 id="horizontal-pod-autoscaler-如何工作" tabindex="-1">Horizontal Pod Autoscaler 如何工作？ <a class="header-anchor" href="#horizontal-pod-autoscaler-如何工作" aria-label="Permalink to &quot;Horizontal Pod Autoscaler 如何工作？&quot;">​</a></h2><p>Horizontal Pod Autoscaler 由一个控制循环实现，循环周期由 controller manager 中的 <code>--horizontal-pod-autoscaler-sync-period</code> 标志指定（默认是 30 秒）。</p><p>在每个周期内，controller manager 会查询 HorizontalPodAutoscaler 中定义的 metric 的资源利用率。Controller manager 从 resource metric API（每个 pod 的 resource metric）或者自定义 metric API（所有的 metric）中获取 metric。</p><ul><li>每个 Pod 的 resource metric（例如 CPU），controller 通过 resource metric API 获取 HorizontalPodAutoscaler 中定义的每个 Pod 中的 metric。然后，如果设置了目标利用率，controller 计算利用的值与每个 Pod 的容器里的 resource request 值的百分比。如果设置了目标原始值，将直接使用该原始 metric 值。然后 controller 计算所有目标 Pod 的利用率或原始值（取决于所指定的目标类型）的平均值，产生一个用于缩放所需 replica 数量的比率。 请注意，如果某些 Pod 的容器没有设置相关的 resource request ，则不会定义 Pod 的 CPU 利用率，并且 Aucoscaler 也不会对该 metric 采取任何操作。</li><li>对于每个 Pod 自定义的 metric，controller 功能类似于每个 Pod 的 resource metric，只是它使用原始值而不是利用率值。</li><li>对于 object metric，获取单个度量（描述有问题的对象），并与目标值进行比较，以产生如上所述的比率。</li></ul><p>HorizontalPodAutoscaler 控制器可以以两种不同的方式获取 metric ：直接的 Heapster 访问和 REST 客户端访问。</p><p>当使用直接的 Heapster 访问时，HorizontalPodAutoscaler 直接通过 API 服务器的服务代理子资源查询 Heapster。需要在集群上部署 Heapster 并在 kube-system namespace 中运行。</p><p>Autoscaler 访问相应的 replication controller，deployment 或 replica set 来缩放子资源。</p><p>Scale 是一个允许您动态设置副本数并检查其当前状态的接口。</p><h2 id="api-object" tabindex="-1">API Object <a class="header-anchor" href="#api-object" aria-label="Permalink to &quot;API Object&quot;">​</a></h2><p>Horizontal Pod Autoscaler 是 kubernetes 的 <code>autoscaling</code> API 组中的 API 资源。当前的稳定版本中，只支持 CPU 自动扩缩容，可以在 <code>autoscaling/v1</code> API 版本中找到。</p><p>在 alpha 版本中支持根据内存和自定义 metric 扩缩容，可以在 <code>autoscaling/v2alpha1</code> 中找到。<code>autoscaling/v2alpha1</code> 中引入的新字段在 <code>autoscaling/v1</code> 中是做为 annotation 而保存的。</p><h2 id="在-kubectl-中支持-horizontal-pod-autoscaling" tabindex="-1">在 kubectl 中支持 Horizontal Pod Autoscaling <a class="header-anchor" href="#在-kubectl-中支持-horizontal-pod-autoscaling" aria-label="Permalink to &quot;在 kubectl 中支持 Horizontal Pod Autoscaling&quot;">​</a></h2><p>Horizontal Pod Autoscaler 和其他的所有 API 资源一样，通过 <code>kubectl</code> 以标准的方式支持。</p><p>我们可以使用 <code>kubectl create</code> 命令创建一个新的 autoscaler。</p><p>我们可以使用 <code>kubectl get hpa</code> 列出所有的 autoscaler，使用 <code>kubectl describe hpa</code> 获取其详细信息。</p><p>最后我们可以使用 <code>kubectl delete hpa</code> 删除 autoscaler。</p><p>另外，可以使用 <code>kubectl autoscale</code> 命令，很轻易的就可以创建一个 Horizontal Pod Autoscaler。</p><p>例如，执行 <code>kubectl autoscale rc foo —min=2 —max=5 —cpu-percent=80</code> 命令将为 replication controller <em>foo</em> 创建一个 autoscaler，目标的 CPU 利用率是 <code>80%</code>，replica 的数量介于 2 和 5 之间。</p><h2 id="滚动更新期间的自动扩缩容" tabindex="-1">滚动更新期间的自动扩缩容 <a class="header-anchor" href="#滚动更新期间的自动扩缩容" aria-label="Permalink to &quot;滚动更新期间的自动扩缩容&quot;">​</a></h2><p>目前在 Kubernetes 中，可以通过直接管理 replication controller 或使用 deployment 对象来执行 滚动更新，该 deployment 对象为您管理基础 replication controller。</p><p>Horizontal Pod Autoscaler 仅支持后一种方法：Horizontal Pod Autoscaler 被绑定到 deployment 对象，它设置 deployment 对象的大小，deployment 负责设置底层 replication controller 的大小。</p><p>Horizontal Pod Autoscaler 不能使用直接操作 replication controller 进行滚动更新，即不能将 Horizontal Pod Autoscaler 绑定到 replication controller，并进行滚动更新（例如使用 <code>kubectl rolling-update</code>）。</p><p>这不行的原因是，当滚动更新创建一个新的 replication controller 时，Horizontal Pod Autoscaler 将不会绑定到新的 replication controller 上。</p><h2 id="支持多个-metric" tabindex="-1">支持多个 metric <a class="header-anchor" href="#支持多个-metric" aria-label="Permalink to &quot;支持多个 metric&quot;">​</a></h2><p>Kubernetes 1.6 中增加了支持基于多个 metric 的扩缩容。您可以使用 <code>autoscaling/v2alpha1</code> API 版本来为 Horizontal Pod Autoscaler 指定多个 metric。然后 Horizontal Pod Autoscaler controller 将权衡每一个 metric，并根据该 metric 提议一个新的 scale。在所有提议里最大的那个 scale 将作为最终的 scale。</p><h2 id="支持自定义-metric" tabindex="-1">支持自定义 metric <a class="header-anchor" href="#支持自定义-metric" aria-label="Permalink to &quot;支持自定义 metric&quot;">​</a></h2><p><strong>注意：</strong> Kubernetes 1.2 根据特定于应用程序的 metric ，通过使用特殊注释的方式，增加了对缩放的 alpha 支持。</p><p>在 Kubernetes 1.6 中删除了对这些注释的支持，有利于 <code>autoscaling/v2alpha1</code> API。 虽然旧的收集自定义 metric 的旧方法仍然可用，但是这些 metric 将不可供 Horizontal Pod Autoscaler 使用，并且用于指定要缩放的自定义 metric 的以前的注释也不在受 Horizontal Pod Autoscaler 认可。</p><p>Kubernetes 1.6 增加了在 Horizontal Pod Autoscale r 中使用自定义 metric 的支持。</p><p>您可以为 <code>autoscaling/v2alpha1</code> API 中使用的 Horizontal Pod Autoscaler 添加自定义 metric 。</p><p>Kubernetes 然后查询新的自定义 metric API 来获取相应自定义 metric 的值。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>为了在 Horizontal Pod Autoscaler 中使用自定义 metric，您必须在您集群的 controller manager 中将 <code>--horizontal-pod-autoscaler-use-rest-clients</code> 标志设置为 true。然后，您必须通过将 controller manager 的目标 API server 设置为 API server aggregator（使用 <code>--apiserver</code> 标志），配置您的 controller manager 通过 API server aggregator 与 API server 通信。 Resource metric API 和自定义 metric API 也必须向 API server aggregator 注册，并且必须由集群上运行的 API server 提供。</p><p>您可以使用 Heapster 实现 resource metric API，方法是将 <code>--api-server</code> 标志设置为 true 并运行 Heapster。 单独的组件必须提供自定义 metric API（有关自定义 metric API 的更多信息，可从 <a href="https://github.com/kubernetes/metrics" target="_blank" rel="noreferrer">k8s.io/metrics repository</a> 获得）。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kubernetes.io/docs/tasks/run-application/horizontal-pod-autoscale/" target="_blank" rel="noreferrer">HPA 说明 - kubernetes.io</a></li><li><a href="https://kubernetes.io/docs/tasks/run-application/horizontal-pod-autoscale-walkthrough/" target="_blank" rel="noreferrer">HPA 详解 - kubernetes.io</a></li><li><a href="https://github.com/kubernetes/metrics" target="_blank" rel="noreferrer">自定义 metrics 开发 - github.com</a></li></ul>`,61);function d(a,u,k,m,b,g){return l(),r("div",null,[e("h1",c,[i(o(a.$frontmatter.title)+" ",1),p]),h])}const F=t(n,[["render",d]]);export{A as __pageData,F as default};
